// ── Population mapping (same as B1.2) ────────────────────────────────────────
const POP_MAPPING = {
    EUR_N:   ['1000GENOMES:phase_3:CEU', '1000GENOMES:phase_3:GBR', '1000GENOMES:phase_3:FIN'],
    EUR_S:   ['1000GENOMES:phase_3:TSI', '1000GENOMES:phase_3:IBS'],
    AFR_W:   ['1000GENOMES:phase_3:YRI', '1000GENOMES:phase_3:GWD', '1000GENOMES:phase_3:MSL', '1000GENOMES:phase_3:ESN'],
    AFR_E:   ['1000GENOMES:phase_3:LWK'],
    EAS_CN:  ['1000GENOMES:phase_3:CHB', '1000GENOMES:phase_3:CHS'],
    EAS_JP:  ['1000GENOMES:phase_3:JPT'],
    SAS:     ['1000GENOMES:phase_3:GIH', '1000GENOMES:phase_3:BEB', '1000GENOMES:phase_3:ITU', '1000GENOMES:phase_3:STU', '1000GENOMES:phase_3:PJL'],
    AMR_NAT: ['1000GENOMES:phase_3:PEL'],
};

function fetchVariant(rsid) {
    return new Promise((resolve) => {
        const opts = {
            hostname: 'rest.ensembl.org',
            path:     `/variation/human/${rsid}?pops=1;content-type=application/json`,
            method:   'GET',
            headers:  { 'User-Agent': 'NURA-research/3.0' }
        };
        const req = https.request(opts, (res) => {
            let data = '';
            res.on('data', c => { data += c; });
            res.on('end', () => {
                if (res.statusCode === 429) { resolve({ _rateLimited: true }); return; }
                if (res.statusCode !== 200) { resolve({ _error: `HTTP ${res.statusCode}` }); return; }
                try { resolve(JSON.parse(data)); }
                catch (e) { resolve({ _error: e.message }); }
            });
        });
        req.on('error', e => resolve({ _error: e.message }));
        req.setTimeout(20000, () => { req.destroy(); resolve({ _timeout: true }); });
        req.end();
    });
}

function computeWeightedFreq(popData, targetPopIds) {
    let totalCount = 0, totalAlleles = 0;
    for (const pd of popData) {
        if (!targetPopIds.includes(pd.population)) continue;
        const freq = pd.frequency ?? 0;
        const n    = pd.allele_count ? Math.round(pd.allele_count / (freq || 1)) : 100;
        totalCount   += freq * n;
        totalAlleles += n;
    }
    return totalAlleles > 0 ? totalCount / totalAlleles : null;
}

async function processAim(aimInfo) {
    let data, attempts = 0;
    while (attempts < 3) {
        data = await fetchVariant(aimInfo.rsid);
        if (data._rateLimited) {
            console.log(`  ⏳ Rate limit — waiting 60s`);
            await new Promise(r => setTimeout(r, 60000));
            continue;
        }
        if (data._timeout || data._error) {
            await new Promise(r => setTimeout(r, 3000 * (attempts + 1)));
            attempts++;
            continue;
        }
        break;
    }

    if (data._error || data._timeout || !data.mappings || !data.populations) {
        return { ...aimInfo, _failed: true };
    }

    // Determine minor allele from the most_severe_consequence or minor_allele field
    const minorAllele = data.minor_allele ?? null;
    if (!minorAllele) return { ...aimInfo, _failed: true, _reason: 'no minor_allele' };

    // Get all alleles
    const alleles = data.most_common_allele
        ? [data.most_common_allele, minorAllele]
        : (data.ambiguity ? null : null);

    const popData = data.populations || [];

    // Compute frequency of minor allele in each sub-population
    const frequencies = {};
    let allNull = true;
    for (const [subpop, pops] of Object.entries(POP_MAPPING)) {
        // Filter popData to only this minor allele in the target populations
        const subPopData = popData
            .filter(p => pops.includes(p.population) && p.allele === minorAllele)
            .map(p => ({ population: p.population, frequency: p.frequency, allele_count: p.allele_count }));

        const freq = computeWeightedFreq(subPopData, pops);
        frequencies[subpop] = freq !== null ? Math.round(freq * 1e6) / 1e6 : 0.5;
        if (freq !== null) allNull = false;
    }

    if (allNull) return { ...aimInfo, _failed: true, _reason: 'no population data' };

    // MAF from PEL (AMR_NAT proxy)
    const pelData = popData.filter(p => p.population === '1000GENOMES:phase_3:PEL' && p.allele === minorAllele);
    const mafChile = pelData.length > 0 ? (pelData[0].frequency ?? 0.5) : 0.5;

    // Major allele (not minor)
    const ancestralAllele = data.ancestral_allele ?? null;
    const majorAllele = (data.mappings?.[0]?.allele_string || '').split('/').find(a => a !== minorAllele) ?? 'N';

    return {
        rsid:        aimInfo.rsid,
        chromosome:  aimInfo.chromosome,
        position:    aimInfo.position,
        minorAllele,
        majorAllele: majorAllele.length === 1 ? majorAllele : 'N',
        MAF_chile:   Math.round(mafChile * 1e6) / 1e6,
        frequencies,
        source:      'Kidd-Seldin-2009-2014',
    };
}

// ── Main ──────────────────────────────────────────────────────────────────────
const OUT = path.join(__dirname, 'new-aims-enriched.json');

async function main() {
    console.log('═══════════════════════════════════════════════════════');
    console.log('  NURA 4.1-E — Fetch Ensembl frequencies: new AIMs');
    console.log(`  ${NEW_AIMS_IN_GSA.length} AIMs to fetch (Kidd+Seldin in MyHeritage GSA)`);
    console.log('═══════════════════════════════════════════════════════\n');

    // Check for existing partial output to resume
    let completed = [];
    if (fs.existsSync(OUT)) {
        completed = JSON.parse(fs.readFileSync(OUT, 'utf8'));
        console.log(`Resuming: ${completed.length} already fetched`);
    }
    const completedRsids = new Set(completed.map(a => a.rsid));

    const remaining = NEW_AIMS_IN_GSA.filter(a => !completedRsids.has(a.rsid));
    console.log(`Remaining: ${remaining.length}\n`);

    let failed = 0;
    for (let i = 0; i < remaining.length; i++) {
        const aim = remaining[i];
        process.stdout.write(`[${completedRsids.size + i + 1}/${NEW_AIMS_IN_GSA.length}] ${aim.rsid}... `);

        const result = await processAim(aim);

        if (result._failed) {
            console.log(`❌ FAILED (${result._reason ?? 'unknown'})`);
            failed++;
        } else {
            console.log(`✅ minorAllele=${result.minorAllele} AMR=${(result.frequencies.AMR_NAT * 100).toFixed(1)}% EUR_S=${(result.frequencies.EUR_S * 100).toFixed(1)}%`);
            completed.push(result);
            completedRsids.add(result.rsid);
        }

        // Save incrementally (resume-safe)
        fs.writeFileSync(OUT, JSON.stringify(completed.filter(r => !r._failed), null, 2));

        // Rate limit: ~3 req/s
        await new Promise(r => setTimeout(r, 350));
    }

    const valid = completed.filter(r => !r._failed);
    console.log(`\n${'═'.repeat(55)}`);
    console.log(`✅ Done: ${valid.length} AIMs fetched | ${failed} failed`);
    console.log(`Output: ${OUT}`);
    console.log(`${'═'.repeat(55)}`);
}

main().catch(e => { console.error('Fatal:', e.message); process.exit(1); });
